1. using System;
2. using System.Collections.Generic;
3. using ContosoUniversity.Data;
4. using ContosoUniversity.Services;
5. using ContosoUniversity.Models;
6. using Microsoft.AspNetCore.Mvc;
7. using Microsoft.Extensions.Configuration;
8. 
9. namespace ContosoUniversity.Controllers
10. {
11.     public class NotificationsController : BaseController
12.     {
13.         public NotificationsController(SchoolContext context) : base(context)
14.         {
15.         }
16. 
17.         // GET: api/notifications - Get pending notifications for admin
18.         [HttpGet]
19.         public JsonResult GetNotifications()
20.         {
21.             var notifications = new List<Notification>();
22.             
23.             try
24.             {
25.                 // Read all available notifications from the queue
26.                 Notification notification;
27.                 while ((notification = notificationService.ReceiveNotification()) != null)
28.                 {
29.                     notifications.Add(notification);
30.                     
31.                     // Limit to prevent overwhelming the UI
32.                     if (notifications.Count >= 10)
33.                         break;
34.                 }
35.             }
36.             catch (Exception ex)
37.             {
38.                 System.Diagnostics.Debug.WriteLine($"Error retrieving notifications: {ex.Message}");
39.                 return Json(new { success = false, message = "Error retrieving notifications" });
40.             }
41. 
42.             return Json(new { 
43.                 success = true, 
43.                 notifications,
44.                 count = notifications.Count 
45.             });
46.         }
47. 
48.         // POST: api/notifications/mark-read
49.         [HttpPost]
50.         public JsonResult MarkAsRead(int id)
51.         {
52.             try
53.             {
54.                 notificationService.MarkAsRead(id);
55.                 return Json(new { success = true });
56.             }
57.             catch (Exception ex)
58.             {
59.                 System.Diagnostics.Debug.WriteLine($"Error marking notification as read: {ex.Message}");
60.                 return Json(new { success = false, message = "Error updating notification" });
61.             }
62.         }
63. 
64.         // GET: Notifications/Index - Admin notification dashboard
65.         public ActionResult Index()
66.         {
66.         {
67.             return View();
68.         }
69.     }
70. }
