95.         // POST: Students/Create
96.         [HttpPost]
97.         [ValidateAntiForgeryToken]
98.         public ActionResult Create([Bind("LastName", "FirstMidName", "EnrollmentDate")] Student student)
99.         {
100.             try
100.             {
101.                 // Validate EnrollmentDate is not default/minimum value
102.                 if (student.EnrollmentDate == DateTime.MinValue || student.EnrollmentDate == default(DateTime))
103.                 {
104.                     ModelState.AddModelError("EnrollmentDate", "Please enter a valid enrollment date.");
105.                 }
106. 
107.                 // Ensure EnrollmentDate is within valid SQL Server datetime range
108.                 if (student.EnrollmentDate < new DateTime(1753, 1, 1) || student.EnrollmentDate > new DateTime(9999, 12, 31))
109.                 {
110.                     ModelState.AddModelError("EnrollmentDate", "Enrollment date must be between 1753 and 9999.");
111.                 }
112. 
113.                 if (ModelState.IsValid)
113.                 {
114.                     db.Students.Add(student);
115.                     db.SaveChanges();
116. 
117.                     // Send notification for student creation
118.                     var studentName = $"{student.FirstMidName} {student.LastName}";
119.                     SendEntityNotification("Student", student.ID.ToString(), studentName, EntityOperation.CREATE);
120. 
120.                     return RedirectToAction("Index");
121.                 }
122.             }
123.             catch (Exception ex)
123.             {
124.                 Trace.TraceError($"Error creating student: {ex.Message} | Student: {student?.FirstMidName} {student?.LastName} | EnrollmentDate: {student?.EnrollmentDate} | Stack: {ex.StackTrace}");
125.                 ModelState.AddModelError("", "Unable to save changes. Try again, and if the problem persists see your system administrator.");
126.             }
127.             return View(student);
128.         }
