5. namespace ContosoUniversity.Services
6. {
7.     public class NotificationService : IDisposable
8.     {
9.         // Static shared queue across application instances (simple in-memory alternative to MSMQ)
10.         private static readonly ConcurrentQueue<Notification> _queue = new();
11.         private static readonly int _maxQueueLength = 500; // basic cap to prevent unbounded growth
12. 
13.         public NotificationService()
14.         {
15.             // No initialization required for in-memory queue
16.         }
17. 
18.         public void SendNotification(string entityType, string entityId, EntityOperation operation, string userName = null)
19.         {
19.             SendNotification(entityType, entityId, null, operation, userName);
20.         }
21. 
22.         public void SendNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation, string userName = null)
23.         {
24.             try
24.             {
25.                 var notification = new Notification
26.                 {
26.                     EntityType = entityType,
27.                     EntityId = entityId,
28.                     Operation = operation.ToString(),
29.                     Message = GenerateMessage(entityType, entityId, entityDisplayName, operation),
30.                     CreatedAt = DateTime.Now,
31.                     CreatedBy = userName ?? "System",
32.                     IsRead = false
33.                 };
34. 
35.                 _queue.Enqueue(notification);
36. 
37.                 // Enforce max queue length (best-effort)
38.                 while (_queue.Count > _maxQueueLength && _queue.TryDequeue(out _)) { }
39.             }
39.             catch (Exception ex)
40.             {
41.                 System.Diagnostics.Debug.WriteLine($"Failed to enqueue notification: {ex.Message}");
42.             }
43.         }
44. 
45.         public Notification ReceiveNotification()
46.         {
46.             try
46.             {
47.                 return _queue.TryDequeue(out var notification) ? notification : null;
48.             }
48.             catch (Exception ex)
49.             {
50.                 System.Diagnostics.Debug.WriteLine($"Failed to receive notification: {ex.Message}");
51.                 return null;
52.             }
53.         }
54. 
55.         public void MarkAsRead(int notificationId)
56.         {
56.             // No-op for in-memory implementation (persistence not implemented)
57.         }
58. 
59.         private string GenerateMessage(string entityType, string entityId, string entityDisplayName, EntityOperation operation)
59.         {
60.             var displayText = !string.IsNullOrWhiteSpace(entityDisplayName)
60.                 ? $"{entityType} '{entityDisplayName}'"
61.                 : $"{entityType} (ID: {entityId})";
62. 
63.             return operation switch
63.             {
64.                 EntityOperation.CREATE => $"New {displayText} has been created",
65.                 EntityOperation.UPDATE => $"{displayText} has been updated",
66.                 EntityOperation.DELETE => $"{displayText} has been deleted",
67.                 _ => $"{displayText} operation: {operation}"
68.             };
69.         }
70. 
71.         public void Dispose()
71.         {
72.             // Nothing to dispose for in-memory queue
73.         }
74.     }
75. }
