5. namespace ContosoUniversity
6. {
7.     public class PaginatedList<T> : List<T>
8.     {
9.         public int PageIndex { get; private set; }
10.         public int TotalPages { get; private set; }
11. 
12.         public PaginatedList(List<T> items, int count, int pageIndex, int pageSize)
12.         {
13.             PageIndex = pageIndex;
14.             TotalPages = (int)Math.Ceiling(count / (double)pageSize);
15. 
16.             this.AddRange(items);
17.         }
18. 
19.         public bool HasPreviousPage => PageIndex > 1;
20. 
21.         public bool HasNextPage => PageIndex < TotalPages;
22. 
23.         public static PaginatedList<T> Create(IQueryable<T> source, int pageIndex, int pageSize)
23.         {
24.             var count = source.Count();
25.             var items = source.Skip((pageIndex - 1) * pageSize).Take(pageSize).ToList();
26.             return new PaginatedList<T>(items, count, pageIndex, pageSize);
27.         }
28.     }
29. 
