        public void Initialize_SeedsCourseAssignments()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(8, _context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_CalledTwice_DoesNotDuplicate()
        {
            DbInitializer.Initialize(_context);
            DbInitializer.Initialize(_context);

            Assert.Equal(8, _context.Students.Count());
        }

        [Fact]
        public void Initialize_WithExistingStudents_SkipsSeeding()
        {
            // Add one student before initialization
            _context.Students.Add(new ContosoUniversity.Models.Student
            {
                FirstMidName = "Existing",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            });
            _context.SaveChanges();

            DbInitializer.Initialize(_context);

            // Only the 1 existing student, no seed data added
            Assert.Equal(1, _context.Students.Count());
        }
    }
}

