        public void DeleteConfirmed_CourseWithImagePath_DeletesFile()
        {
            // Set up a course with an image path
            var course = _context.Courses.Find(1050);
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var testFilePath = Path.Combine(uploadsDir, "test_image.jpg");
            File.WriteAllText(testFilePath, "dummy");
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(1050);

            Assert.False(File.Exists(testFilePath));
        }

        #endregion

        #region Helpers

        private Mock<Microsoft.AspNetCore.Http.IFormFile> CreateMockFormFile(string fileName, long length)
        {
            var fileMock = new Mock<Microsoft.AspNetCore.Http.IFormFile>();
            var ms = new MemoryStream(new byte[Math.Min(length, 1024)]); // small buffer is fine for tests
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s =>
            {
                ms.Position = 0;
                ms.CopyTo(s);
            });
            return fileMock;
        }

        #endregion
    }
}

