            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 101,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            Assert.Equal(1, _context.Courses.Count());
        }

        [Fact]
        public void Context_CanCreateEnrollments()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Today
            };
            _context.Students.Add(student);

            var dept = new Department { Name = "Test", Budget = 10000, StartDate = DateTime.Today };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 100,
                Title = "Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
            };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            Assert.Equal(1, _context.Enrollments.Count());
        }

        [Fact]
        public void Context_CanCreateNotifications()
        {
            var notification = new Notification
            {
                EntityType = "Test",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };
            _context.Notifications.Add(notification);
            _context.SaveChanges();

            Assert.Equal(1, _context.Notifications.Count());
        }

        [Fact]
        public void Context_CourseAssignment_HasCompositeKey()
        {
            var instructor = new Instructor { FirstMidName = "Test", LastName = "Inst", HireDate = DateTime.Today };
            _context.Instructors.Add(instructor);

            var dept = new Department { Name = "Dept", Budget = 10000, StartDate = DateTime.Today };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 200, Title = "Course", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var ca = new CourseAssignment { CourseID = course.CourseID, InstructorID = instructor.ID };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            var found = _context.CourseAssignments.Find(course.CourseID, instructor.ID);
            Assert.NotNull(found);
        }

        [Fact]
        public void Context_DbSets_AreNotNull()
        {
            Assert.NotNull(_context.Courses);
            Assert.NotNull(_context.Enrollments);
            Assert.NotNull(_context.Departments);
            Assert.NotNull(_context.OfficeAssignments);
            Assert.NotNull(_context.CourseAssignments);
            Assert.NotNull(_context.People);
            Assert.NotNull(_context.Students);
            Assert.NotNull(_context.Instructors);
            Assert.NotNull(_context.Notifications);
        }
    }
