        private Mock<Microsoft.AspNetCore.Http.IFormFile> CreateMockFormFile(string fileName, long length)
        {
            var fileMock = new Mock<Microsoft.AspNetCore.Http.IFormFile>();
            var ms = new MemoryStream(new byte[Math.Min(length, 1024)]); // small buffer is fine for tests
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s =>
            {
                ms.Position = 0;
                ms.CopyTo(s);
            });
            return fileMock;
        }

        #endregion
    }
