using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_WithSearchString_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_WithSearchString_SetsPageTo1()
        {
            var result = _controller.Index(null, null, "A", 5);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_WithNullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SortByNameDesc_ReturnsSortedResults()
        {
            var result = _controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.True(model.Count > 1);
            Assert.True(string.Compare(model[0].LastName, model[1].LastName) > 0);
        }

        [Fact]
        public void Index_SortByDate_ReturnsSortedResults()
        {
            var result = _controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.True(model[0].EnrollmentDate <= model[1].EnrollmentDate);
        }

        [Fact]
        public void Index_SortByDateDesc_ReturnsSortedResults()
        {
            var result = _controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.True(model[0].EnrollmentDate >= model[1].EnrollmentDate);
        }

        [Fact]
        public void Index_DefaultSort_ReturnsByLastNameAsc()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.True(string.Compare(model[0].LastName, model[1].LastName) <= 0);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("name_desc", viewResult.ViewData["NameSortParm"]);
            Assert.Equal("Date", viewResult.ViewData["DateSortParm"]);
        }

        [Fact]
        public void Index_WithNameDescSort_SetsCorrectSortParms()
        {
            _controller.Index("name_desc", null, null, null);

            Assert.Equal("", _controller.ViewBag.NameSortParm as string);
        }

        [Fact]
        public void Index_WithDateSort_SetsDateDescSortParm()
        {
            _controller.Index("Date", null, null, null);

            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm as string);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_WithValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Details(10);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Carson", model.FirstMidName);
            Assert.Equal("Alexander", model.LastName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2024-01-15")
            };

            var result = _controller.Create(student);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_SavesStudent()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Person",
                EnrollmentDate = DateTime.Parse("2024-06-01")
            };

            _controller.Create(student);

            Assert.True(_context.Students.Any(s => s.LastName == "Person"));
        }

        [Fact]
        public void Create_Post_InvalidEnrollmentDate_ReturnsView()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Student>(viewResult.Model);
        }

        [Fact]
        public void Create_Post_DateBelow1753_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1700, 1, 1)
            };

            _controller.Create(student);

            Assert.True(_controller.ModelState.ErrorCount > 0);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student { FirstMidName = "Test", EnrollmentDate = DateTime.Today };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Student>(viewResult.Model);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_WithValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(10);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                ID = 10,
                FirstMidName = "Carson",
                LastName = "Updated",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };
            // Detach the tracked entity first
            var tracked = _context.Students.Find(10);
            _context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 10,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };

            var result = _controller.Edit(student);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Post_MinDateEnrollment_ReturnsViewWithError()
        {
            var student = new Student
            {
                ID = 10,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ErrorCount > 0);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_WithValidId_ReturnsView()
        {
            var result = _controller.Delete(10);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(10);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Students.Find(10));
        }

        [Fact]
        public void DeleteConfirmed_InvalidId_RedirectsWithError()
        {
            // Calling with a non-existent ID triggers the catch block
            var result = _controller.DeleteConfirmed(999);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        #endregion
    }
}

