                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", 6 * 1024 * 1024);

            var result = _controller.Create(course, mockFile.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

