        public void Create_Post_WithValidImage_SavesAndRedirects()
        {
            var course = new Course
            {
                CourseID = 7779,
                Title = "Course with Image",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", 1024);

            var result = _controller.Create(course, mockFile.Object);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            var savedCourse = _context.Courses.Find(7779);
            Assert.NotNull(savedCourse);
            Assert.StartsWith("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

