using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_NoParams_ReturnsViewWithAllInstructors()
        {
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.Equal(3, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ReturnsCoursesForInstructor()
        {
            var result = _controller.Index(3, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.True(model.Courses.Any());
        }

        [Fact]
        public void Index_WithInstructorAndCourseId_ReturnsEnrollments()
        {
            var result = _controller.Index(3, 1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Index_SetsViewBagInstructorID()
        {
            _controller.Index(1, null);

            Assert.Equal(1, _controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_SetsViewBagCourseID()
        {
            _controller.Index(3, 1050);

            Assert.Equal(1050, _controller.ViewBag.CourseID);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Kim", model.FirstMidName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithAssignedCourseData()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
            var courseData = Assert.IsAssignableFrom<List<AssignedCourseData>>(_controller.ViewBag.Courses);
            Assert.Equal(3, courseData.Count);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                LastName = "Smith",
                HireDate = DateTime.Parse("2020-01-15")
            };

            var result = _controller.Create(instructor, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidInstructor_SavesToDB()
        {
            var instructor = new Instructor
            {
                FirstMidName = "NewFirst",
                LastName = "NewLast",
                HireDate = DateTime.Parse("2020-06-15")
            };

            _controller.Create(instructor, null);

            Assert.True(_context.Instructors.Any(i => i.LastName == "NewLast"));
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Course",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-15")
            };

            _controller.Create(instructor, new[] { "1050", "4022" });

            var saved = _context.Instructors.First(i => i.LastName == "Instructor");
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.Equal(2, assignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Today
            };

            var result = _controller.Create(instructor, null);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Edit(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Delete(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        #endregion

        #region DeleteConfirmed

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Instructors.Find(1));
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            // Instructor 1 is the administrator of Department 1 (English)
            _controller.DeleteConfirmed(1);

            var dept = _context.Departments.Find(1);
            Assert.Null(dept.InstructorID);
        }

        #endregion
    }
}

