using ContosoUniversity.Models;
using System.ComponentModel.DataAnnotations;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        #region Person / FullName

        [Fact]
        public void Student_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student { FirstMidName = "Carson", LastName = "Alexander" };

            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void Instructor_FullName_ReturnsLastNameCommaFirstName()
        {
            var instructor = new Instructor { FirstMidName = "Kim", LastName = "Abercrombie" };

            Assert.Equal("Abercrombie, Kim", instructor.FullName);
        }

        #endregion

        #region Course

        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/uploads/test.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/uploads/test.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_Title_HasStringLengthAttribute()
        {
            var prop = typeof(Course).GetProperty("Title");
            var attr = prop.GetCustomAttributes(typeof(StringLengthAttribute), false).FirstOrDefault() as StringLengthAttribute;
            Assert.NotNull(attr);
            Assert.Equal(50, attr.MaximumLength);
            Assert.Equal(3, attr.MinimumLength);
        }

        [Fact]
        public void Course_Credits_HasRangeAttribute()
        {
            var prop = typeof(Course).GetProperty("Credits");
            var attr = prop.GetCustomAttributes(typeof(RangeAttribute), false).FirstOrDefault() as RangeAttribute;
            Assert.NotNull(attr);
            Assert.Equal(0, attr.Minimum);
            Assert.Equal(5, attr.Maximum);
        }

        #endregion

        #region Department

        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = 1
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("English", dept.Name);
            Assert.Equal(350000, dept.Budget);
            Assert.Equal(1, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_IsNullable()
        {
